import type { Metadata, Viewport } from 'next';
import { Inter } from 'next/font/google';
import { ThemeProvider } from '@/components/theme-provider';
import './globals.css';

const inter = Inter({
  subsets: ['latin'],
  variable: '--font-sans',
});

export const metadata: Metadata = {
  title: 'Lazy Golfing - Track Your Golf Game',
  description:
    'The comprehensive golf tracking platform for rounds, leagues, tournaments, and more. Track your handicap, connect with playing partners, and improve your game.',
  keywords: [
    'golf',
    'golf tracking',
    'handicap',
    'golf rounds',
    'golf leagues',
    'golf tournaments',
  ],
  authors: [{ name: 'Lazy Golfing' }],
  creator: 'Lazy Golfing',
  icons: {
    icon: [
      { url: '/favicon.ico', sizes: 'any' },
      { url: '/favicon-32x32.png', sizes: '32x32', type: 'image/png' },
      { url: '/favicon-16x16.png', sizes: '16x16', type: 'image/png' },
    ],
    apple: { url: '/apple-touch-icon.png', sizes: '180x180' },
  },
  manifest: '/site.webmanifest',
  openGraph: {
    type: 'website',
    locale: 'en_US',
    url: 'https://lazygolfing.com',
    siteName: 'Lazy Golfing',
    title: 'Lazy Golfing - Track Your Golf Game',
    description:
      'The comprehensive golf tracking platform for rounds, leagues, tournaments, and more.',
    images: [
      {
        url: '/og-image.png',
        width: 1200,
        height: 630,
        alt: 'Lazy Golfing - Track Your Golf Game',
      },
    ],
  },
  twitter: {
    card: 'summary_large_image',
    title: 'Lazy Golfing - Track Your Golf Game',
    description:
      'The comprehensive golf tracking platform for rounds, leagues, tournaments, and more.',
    images: ['/og-image.png'],
  },
  robots: {
    index: true,
    follow: true,
  },
};

export const viewport: Viewport = {
  width: 'device-width',
  initialScale: 1,
  themeColor: [
    { media: '(prefers-color-scheme: light)', color: '#ffffff' },
    { media: '(prefers-color-scheme: dark)', color: '#0a0a0a' },
  ],
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="en" suppressHydrationWarning>
      <body className={`${inter.variable} font-sans antialiased`}>
        <ThemeProvider
          attribute="class"
          defaultTheme="system"
          enableSystem
          disableTransitionOnChange
        >
          {children}
        </ThemeProvider>
      </body>
    </html>
  );
}

