export const sportsOrganizationSchema = {
  '@context': 'https://schema.org',
  '@type': 'SportsOrganization',
  name: 'Lazy Golfing',
  url: 'https://lazygolfing.com',
  sport: 'Golf',
  description: 'Golf tracking platform for recreational golfers, leagues, and tournaments.',
};

/**
 * Factory functions for dynamic Schema.org objects
 */

export function createBreadcrumbSchema(items: { name: string; url: string }[]) {
  return {
    '@context': 'https://schema.org',
    '@type': 'BreadcrumbList',
    itemListElement: items.map((item, index) => ({
      '@type': 'ListItem',
      position: index + 1,
      name: item.name,
      item: item.url,
    })),
  };
}

export function createSportsEventSchema(options: {
  name: string;
  startDate: string;
  endDate?: string;
  location?: string;
  description?: string;
  url?: string;
}) {
  return {
    '@context': 'https://schema.org',
    '@type': 'SportsEvent',
    name: options.name,
    startDate: options.startDate,
    endDate: options.endDate,
    location: options.location
      ? {
          '@type': 'Place',
          name: options.location,
        }
      : undefined,
    description: options.description,
    url: options.url,
    sport: 'Golf',
  };
}

export function createGolfCourseSchema(options: {
  name: string;
  address: {
    streetAddress: string;
    addressLocality: string;
    addressRegion: string;
    postalCode: string;
    addressCountry: string;
  };
  telephone?: string;
  url?: string;
  geo?: { latitude: number; longitude: number };
}) {
  return {
    '@context': 'https://schema.org',
    '@type': 'GolfCourse',
    name: options.name,
    address: {
      '@type': 'PostalAddress',
      ...options.address,
    },
    telephone: options.telephone,
    url: options.url,
    geo: options.geo
      ? {
          '@type': 'GeoCoordinates',
          latitude: options.geo.latitude,
          longitude: options.geo.longitude,
        }
      : undefined,
  };
}

