import type { Metadata } from 'next';

/**
 * Centralized Metadata Configuration
 *
 * This file is the SINGLE SOURCE OF TRUTH for all SEO metadata.
 * Update values here to change them across the entire platform.
 *
 * Usage in pages:
 * - Import `createMetadata` for page-specific metadata
 * - Import `siteConfig` for access to raw values
 */

// =============================================================================
// Site Configuration
// =============================================================================

export const siteConfig = {
  name: 'Lazy Golfing',
  tagline: 'Lazy golf for lazy golfers!',
  slogan: 'Cart golf only!',
  description:
    'The comprehensive golf tracking platform for rounds, leagues, tournaments, and more. Track your handicap, connect with playing partners, and improve your game.',
  shortDescription:
    'The comprehensive golf tracking platform for rounds, leagues, tournaments, and more.',
  url: 'https://lazygolfing.com',
  ogImage: '/og-image.png',
  ogImageAlt: 'Lazy Golfing - Track Your Golf Game',
  ogImageWidth: 1200,
  ogImageHeight: 630,
  twitterHandle: '@lazygolfing', // Update when available
  locale: 'en_US',
  keywords: [
    'golf',
    'golf tracking',
    'handicap',
    'golf rounds',
    'golf leagues',
    'golf tournaments',
    'golf stats',
    'golf scoring',
    'golf app',
    'golf platform',
  ],
  author: {
    name: 'Lazy Golfing',
  },
} as const;

// =============================================================================
// Base Metadata (used in root layout)
// =============================================================================

export const baseMetadata: Metadata = {
  metadataBase: new URL(siteConfig.url),
  title: {
    default: `${siteConfig.name} - Track Your Golf Game`,
    template: `%s | ${siteConfig.name}`,
  },
  description: siteConfig.description,
  keywords: siteConfig.keywords,
  authors: [siteConfig.author],
  creator: siteConfig.name,
  publisher: siteConfig.name,
  robots: {
    index: true,
    follow: true,
    googleBot: {
      index: true,
      follow: true,
      'max-video-preview': -1,
      'max-image-preview': 'large',
      'max-snippet': -1,
    },
  },
  icons: {
    icon: [
      { url: '/favicon.ico', sizes: 'any' },
      { url: '/favicon-32x32.png', sizes: '32x32', type: 'image/png' },
      { url: '/favicon-16x16.png', sizes: '16x16', type: 'image/png' },
    ],
    apple: { url: '/apple-touch-icon.png', sizes: '180x180' },
  },
  manifest: '/site.webmanifest',
  openGraph: {
    type: 'website',
    locale: siteConfig.locale,
    url: siteConfig.url,
    siteName: siteConfig.name,
    title: `${siteConfig.name} - Track Your Golf Game`,
    description: siteConfig.shortDescription,
    images: [
      {
        url: siteConfig.ogImage,
        width: siteConfig.ogImageWidth,
        height: siteConfig.ogImageHeight,
        alt: siteConfig.ogImageAlt,
      },
    ],
  },
  twitter: {
    card: 'summary_large_image',
    title: `${siteConfig.name} - Track Your Golf Game`,
    description: siteConfig.shortDescription,
    images: [siteConfig.ogImage],
    // creator: siteConfig.twitterHandle, // Uncomment when handle is active
  },
};

// =============================================================================
// Viewport Configuration
// =============================================================================

export const viewportConfig = {
  width: 'device-width',
  initialScale: 1,
  themeColor: [
    { media: '(prefers-color-scheme: light)', color: '#ffffff' },
    { media: '(prefers-color-scheme: dark)', color: '#0a0a0a' },
  ],
} as const;

// =============================================================================
// Metadata Factory Functions
// =============================================================================

/**
 * Create page-specific metadata that merges with base metadata
 *
 * @example
 * // In a page file:
 * export const metadata = createMetadata({
 *   title: 'Rounds',
 *   description: 'Track and view your golf rounds',
 *   path: '/rounds',
 * });
 */
export function createMetadata(options: {
  title: string;
  description?: string;
  path?: string;
  image?: string;
  noIndex?: boolean;
}): Metadata {
  const { title, description, path, image, noIndex } = options;
  const url = path ? `${siteConfig.url}${path}` : siteConfig.url;
  const ogImage = image || siteConfig.ogImage;

  return {
    title,
    description: description || siteConfig.shortDescription,
    ...(noIndex && {
      robots: {
        index: false,
        follow: false,
      },
    }),
    openGraph: {
      title: `${title} | ${siteConfig.name}`,
      description: description || siteConfig.shortDescription,
      url,
      images: [
        {
          url: ogImage,
          width: siteConfig.ogImageWidth,
          height: siteConfig.ogImageHeight,
          alt: `${title} - ${siteConfig.name}`,
        },
      ],
    },
    twitter: {
      title: `${title} | ${siteConfig.name}`,
      description: description || siteConfig.shortDescription,
      images: [ogImage],
    },
    alternates: {
      canonical: url,
    },
  };
}

/**
 * Create metadata for dynamic pages (e.g., course details, player profiles)
 *
 * @example
 * // In a dynamic page [id]/page.tsx:
 * export async function generateMetadata({ params }) {
 *   const course = await getCourse(params.id);
 *   return createDynamicMetadata({
 *     title: course.name,
 *     description: `Play ${course.name} - Par ${course.par}`,
 *     path: `/courses/${params.id}`,
 *   });
 * }
 */
export function createDynamicMetadata(options: {
  title: string;
  description: string;
  path: string;
  image?: string;
  type?: 'article' | 'profile' | 'website';
  publishedTime?: string;
  modifiedTime?: string;
}): Metadata {
  const {
    title,
    description,
    path,
    image,
    type = 'website',
    publishedTime,
    modifiedTime,
  } = options;

  const url = `${siteConfig.url}${path}`;
  const ogImage = image || siteConfig.ogImage;

  return {
    title,
    description,
    openGraph: {
      title: `${title} | ${siteConfig.name}`,
      description,
      url,
      type,
      ...(publishedTime && { publishedTime }),
      ...(modifiedTime && { modifiedTime }),
      images: [
        {
          url: ogImage,
          width: siteConfig.ogImageWidth,
          height: siteConfig.ogImageHeight,
          alt: title,
        },
      ],
    },
    twitter: {
      title: `${title} | ${siteConfig.name}`,
      description,
      images: [ogImage],
    },
    alternates: {
      canonical: url,
    },
  };
}

