--magenta-500: #FF4DA6;  /* Bright variant */
--magenta-300: #FF7EC7;  /* Light tints */
--magenta-100: #FFACE9;
--magenta-50: #FFE5F4;

/* Electric Cyan (Secondary Accent) */
